    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("saveItem", "sites", JsonSerializer.Serialize(site, JsonOptions));
    }

    public async Task<List<ConstructionSite>> GetAllSitesAsync()
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getAllItems", "sites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(json, JsonOptions) ?? new();
    }

    public async Task DeleteSiteAsync(string id)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("deleteItem", "sites", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("saveItem", "inspections", JsonSerializer.Serialize(inspection, JsonOptions));
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string?>("getItem", "inspections", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getItemsByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getItemsByIndex", "inspections", "isSynced", false);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task DeleteInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("deleteItem", "inspections", id);
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }
}

using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService
{
    private readonly HttpClient _http;
    private readonly LocalStorageService _storage;

    public event Action<SyncStatus>? OnSyncStatusChanged;

    public SyncStatus CurrentStatus { get; private set; } = SyncStatus.Idle;

    public SyncService(HttpClient http, LocalStorageService storage)
    {
        _http = http;
        _storage = storage;
    }

    public async Task<SyncResult> SyncAsync()
    {
        var result = new SyncResult();
        CurrentStatus = SyncStatus.Syncing;
        OnSyncStatusChanged?.Invoke(CurrentStatus);

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _storage.SaveInspectionAsync(inspection);
                        result.SyncedCount++;
                    }
                    else
                    {
                        result.FailedCount++;
                    }
                }
                catch
                {
                    result.FailedCount++;
                }
            }

            CurrentStatus = result.FailedCount == 0 ? SyncStatus.Idle : SyncStatus.Error;
        }
        catch
        {
            CurrentStatus = SyncStatus.Offline;
        }

        OnSyncStatusChanged?.Invoke(CurrentStatus);
        return result;
    }

    public async Task<bool> CheckConnectivityAsync()
    {
        try
        {
            var response = await _http.GetAsync("/api/health");
            return response.IsSuccessStatusCode;
        }
        catch
        {
            return false;
        }
    }
}

public class SyncResult
{
    public int SyncedCount { get; set; }
    public int FailedCount { get; set; }
}

public enum SyncStatus
{
    Idle,
    Syncing,
    Offline,
    Error
}

