arguments.file_text:
@page "/"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>My Sites</h1>
    <button class="btn btn-primary btn-lg" @onclick="ShowAddSite">
        <span class="icon">+</span> Add Site
    </button>
</div>

@if (_showAddForm)
{
    <div class="card add-site-card">
        <div class="card-body">
            <input @bind="_newSiteName" @bind:event="oninput" placeholder="Site name" class="form-control form-control-lg mb-2" />
            <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="Address" class="form-control mb-3" />
            <div class="d-flex gap-2">
                <button class="btn btn-success flex-fill" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
                <button class="btn btn-outline-secondary flex-fill" @onclick="CancelAdd">Cancel</button>
            </div>
        </div>
    </div>
}

@if (_sites is null)
{
    <p class="loading">Loading sites...</p>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <div class="empty-icon">🏗️</div>
        <p>No construction sites yet.</p>
        <p class="text-muted">Tap "Add Site" to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="site-card" @onclick="() => NavigateToSite(site.Id)">
                <div class="site-info">
                    <h3>@site.Name</h3>
                    <p class="site-address">@site.Address</p>
                    <p class="site-meta">@_inspectionCounts.GetValueOrDefault(site.Id, 0) inspections</p>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>
}

@code {
    private List<ConstructionSite>? _sites;
    private Dictionary<string, int> _inspectionCounts = new();
    private bool _showAddForm;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _sites = await Storage.GetAllSitesAsync();
        foreach (var site in _sites)
        {
            var inspections = await Storage.GetInspectionsForSiteAsync(site.Id);
            _inspectionCounts[site.Id] = inspections.Count;
        }
    }

    private void ShowAddSite() => _showAddForm = true;
    private void CancelAdd()
    {
        _showAddForm = false;
        _newSiteName = string.Empty;
        _newSiteAddress = string.Empty;
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new ConstructionSite
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };
        await Storage.SaveSiteAsync(site);
        _sites!.Add(site);
        CancelAdd();
    }

    private void NavigateToSite(string siteId) => Nav.NavigateTo($"/site/{siteId}");
}

@page "/site/{SiteId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Details</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
</div>

@if (_site is not null)
{
    <div class="action-bar">
        <button class="btn btn-primary btn-lg btn-block" @onclick="StartInspection">
            📋 New Inspection
        </button>
    </div>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <div class="empty-icon">📋</div>
            <p>No inspections yet for this site.</p>
            <p class="text-muted">Tap "New Inspection" to begin.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectedAt))
            {
                <div class="inspection-card" @onclick="() => ViewInspection(inspection.Id)">
                    <div class="inspection-info">
                        <div class="inspection-date">@inspection.InspectedAt.ToLocalTime().ToString("MMM dd, yyyy HH:mm")</div>
                        <div class="inspection-meta">
                            <span class="badge @GetStatusBadge(inspection.Status)">@inspection.Status</span>
                            <span class="checklist-summary">
                                @GetChecklistSummary(inspection)
                            </span>
                        </div>
                        @if (!string.IsNullOrEmpty(inspection.InspectorName))
                        {
                            <div class="inspector-name">By @inspection.InspectorName</div>
                        }
                    </div>
                    <div class="sync-indicator">
                        @if (inspection.IsSynced)
                        {
                            <span class="synced" title="Synced">☁️</span>
                        }
                        else
                        {
                            <span class="unsynced" title="Not synced">📱</span>
                        }
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Storage.GetAllSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        if (_site is not null)
        {
            _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
        }
    }

    private void GoBack() => Nav.NavigateTo("/");

    private void StartInspection() => Nav.NavigateTo($"/inspect/{SiteId}");

    private void ViewInspection(string id) => Nav.NavigateTo($"/inspection/{id}");

    private string GetStatusBadge(InspectionStatus status) => status switch
    {
        InspectionStatus.InProgress => "bg-warning",
        InspectionStatus.Completed => "bg-success",
        _ => "bg-secondary"
    };

    private string GetChecklistSummary(Inspection inspection)
    {
        var total = inspection.Checklist.Count;
        var passed = inspection.Checklist.Count(c => c.Result == CheckResult.Pass);
        var failed = inspection.Checklist.Count(c => c.Result == CheckResult.Fail);
        return $"✓{passed} ✗{failed} of {total}";
    }
}

@page "/inspect/{SiteId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>New Inspection</PageTitle>

<div class="page-header compact">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>Safety Inspection</h1>
</div>

<div class="inspector-input">
    <input @bind="_inspectorName" @bind:event="oninput" placeholder="Inspector name" class="form-control" />
</div>

<div class="checklist-container">
    @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
    {
        <div class="checklist-category">
            <h3 class="category-header">@category.Key</h3>
            @foreach (var item in category)
            {
                <div class="checklist-item @GetItemClass(item.Result)">
                    <div class="item-description">@item.Description</div>
                    <div class="item-actions">
                        <button class="btn-check-result @(item.Result == CheckResult.Pass ? "active-pass" : "")"
                                @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                        <button class="btn-check-result @(item.Result == CheckResult.Fail ? "active-fail" : "")"
                                @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                        <button class="btn-check-result btn-na @(item.Result == CheckResult.NotApplicable ? "active-na" : "")"
                                @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                    </div>
                    @if (item.Result == CheckResult.Fail)
                    {
                        <input @bind="item.Comment" @bind:event="oninput"
                               placeholder="Add comment about failure..."
                               class="form-control item-comment" />
                    }
                </div>
            }
        </div>
