              class="form-control" rows="4"></textarea>
</div>

<div class="photo-section">
    <h3>Photos (@_inspection.Photos.Count)</h3>
    <label class="btn btn-outline-primary btn-photo">
        📷 Take / Add Photo
        <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" class="d-none" />
    </label>

    @if (_inspection.Photos.Any())
    {
        <div class="photo-grid">
            @foreach (var photo in _inspection.Photos)
            {
                <div class="photo-thumbnail">
                    <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                    <input @bind="photo.Caption" @bind:event="oninput" placeholder="Caption" class="photo-caption" />
                    <button class="btn-remove-photo" @onclick="() => RemovePhoto(photo)">×</button>
                </div>
            }
        </div>
    }
</div>

<div class="form-actions">
    <button class="btn btn-success btn-lg btn-block" @onclick="CompleteInspection">
        ✓ Complete Inspection
    </button>
    <button class="btn btn-outline-secondary btn-lg btn-block" @onclick="SaveDraft">
        💾 Save Draft
    </button>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Inspection _inspection = new();
    private string _inspectorName = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        var sites = await Storage.GetAllSitesAsync();
        var site = sites.FirstOrDefault(s => s.Id == SiteId);

        _inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = site?.Name ?? "Unknown Site",
            Checklist = SafetyChecklists.GetDefaultChecklist()
        };
    }

    private void SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
    }

    private string GetItemClass(CheckResult result) => result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // skip files > 10MB

            using var stream = file.OpenReadStream(10 * 1024 * 1024);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);
            var base64 = Convert.ToBase64String(ms.ToArray());

            _inspection.Photos.Add(new InspectionPhoto
            {
                FileName = file.Name,
                Base64Data = base64,
                TakenAt = DateTime.UtcNow
            });
        }
    }

    private void RemovePhoto(InspectionPhoto photo)
    {
        _inspection.Photos.Remove(photo);
    }

    private async Task SaveDraft()
    {
        _inspection.InspectorName = _inspectorName;
        _inspection.Status = InspectionStatus.InProgress;
        await Storage.SaveInspectionAsync(_inspection);
        Nav.NavigateTo($"/site/{SiteId}");
    }

    private async Task CompleteInspection()
    {
        _inspection.InspectorName = _inspectorName;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.InspectedAt = DateTime.UtcNow;
        await Storage.SaveInspectionAsync(_inspection);
        Nav.NavigateTo($"/site/{SiteId}");
    }

    private void GoBack() => Nav.NavigateTo($"/site/{SiteId}");
}
