@page "/inspection/{InspectionId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Inspection Report</PageTitle>

<div class="page-header compact">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>Inspection Report</h1>
</div>

@if (_inspection is null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="report-header">
        <div class="report-meta">
            <div><strong>Site:</strong> @_inspection.SiteName</div>
            <div><strong>Inspector:</strong> @(_inspection.InspectorName ?? "—")</div>
            <div><strong>Date:</strong> @_inspection.InspectedAt.ToLocalTime().ToString("MMMM dd, yyyy HH:mm")</div>
            <div>
                <strong>Status:</strong>
                <span class="badge @(_inspection.Status == InspectionStatus.Completed ? "bg-success" : "bg-warning")">
                    @_inspection.Status
                </span>
                @if (!_inspection.IsSynced)
                {
                    <span class="badge bg-info">Local only</span>
                }
            </div>
        </div>
    </div>

    <div class="report-summary">
        <div class="summary-stat pass">
            <span class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.Pass)</span>
            <span class="stat-label">Pass</span>
        </div>
        <div class="summary-stat fail">
            <span class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.Fail)</span>
            <span class="stat-label">Fail</span>
        </div>
        <div class="summary-stat na">
            <span class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.NotApplicable)</span>
            <span class="stat-label">N/A</span>
        </div>
        <div class="summary-stat unchecked">
            <span class="stat-number">@_inspection.Checklist.Count(c => c.Result == CheckResult.NotChecked)</span>
            <span class="stat-label">Skipped</span>
        </div>
    </div>

    @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
    {
        <div class="report-category">
            <h3>@category.Key</h3>
            @foreach (var item in category)
            {
                <div class="report-item @GetItemClass(item.Result)">
                    <span class="result-icon">@GetResultIcon(item.Result)</span>
                    <span class="item-text">@item.Description</span>
                    @if (!string.IsNullOrEmpty(item.Comment))
                    {
                        <div class="item-comment-display">💬 @item.Comment</div>
                    }
                </div>
            }
        </div>
    }

    @if (!string.IsNullOrWhiteSpace(_inspection.Notes))
    {
        <div class="report-notes">
            <h3>Notes</h3>
            <p>@_inspection.Notes</p>
        </div>
    }

    @if (_inspection.Photos.Any())
    {
        <div class="report-photos">
            <h3>Photos (@_inspection.Photos.Count)</h3>
            <div class="photo-grid-report">
                @foreach (var photo in _inspection.Photos)
                {
                    <div class="report-photo">
                        <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                        @if (!string.IsNullOrEmpty(photo.Caption))
                        {
                            <div class="photo-caption-display">@photo.Caption</div>
                        }
                    </div>
                }
            </div>
        </div>
    }

    @if (_inspection.Status == InspectionStatus.InProgress)
    {
        <div class="form-actions">
            <button class="btn btn-primary btn-lg btn-block" @onclick="ContinueEditing">
                ✏️ Continue Editing
            </button>
        </div>
    }
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }

    private void ContinueEditing()
    {
        Nav.NavigateTo($"/inspect/{_inspection!.SiteId}");
    }

    private string GetItemClass(CheckResult result) => result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => "item-unchecked"
    };

    private string GetResultIcon(CheckResult result) => result switch
    {
        CheckResult.Pass => "✓",
        CheckResult.Fail => "✗",
        CheckResult.NotApplicable => "—",
        _ => "○"
    };
}

@page "/sync"
@inject SyncService Sync
@inject LocalStorageService Storage

<PageTitle>Sync Status</PageTitle>

<div class="page-header">
    <h1>Sync</h1>
</div>

<div class="sync-page">
    <div class="connectivity-status">
        @if (_isOnline == null)
        {
            <div class="status-indicator checking">Checking connectivity...</div>
        }
        else if (_isOnline == true)
        {
            <div class="status-indicator online">🟢 Online</div>
        }
        else
        {
            <div class="status-indicator offline">🔴 Offline</div>
        }
    </div>

    <div class="sync-stats">
        <div class="stat-card">
            <div class="stat-value">@_unsyncedCount</div>
            <div class="stat-label">Pending Upload</div>
        </div>
        <div class="stat-card">
            <div class="stat-value">@_totalCount</div>
            <div class="stat-label">Total Inspections</div>
        </div>
    </div>

    @if (_unsyncedCount > 0)
    {
        <button class="btn btn-primary btn-lg btn-block" @onclick="DoSync" disabled="@_isSyncing">
            @if (_isSyncing)
            {
                <span>Syncing...</span>
            }
            else
            {
                <span>☁️ Sync Now</span>
            }
        </button>
    }

    @if (_lastResult is not null)
    {
        <div class="sync-result @(_lastResult.FailedCount > 0 ? "has-errors" : "success")">
            @if (_lastResult.SyncedCount > 0)
            {
                <p>✓ @_lastResult.SyncedCount inspection(s) synced successfully.</p>
            }
            @if (_lastResult.FailedCount > 0)
            {
                <p>✗ @_lastResult.FailedCount inspection(s) failed to sync. They will retry on next sync.</p>
            }
        </div>
    }

    <div class="sync-info">
        <p>📱 All inspections are saved locally on your device.</p>
        <p>☁️ When connected, tap "Sync Now" to upload completed inspections to the server.</p>
        <p>💡 You can continue working offline — data will sync when connectivity returns.</p>
    </div>
</div>

@code {
    private bool? _isOnline;
    private bool _isSyncing;
    private int _unsyncedCount;
    private int _totalCount;
    private SyncResult? _lastResult;

    protected override async Task OnInitializedAsync()
    {
        await LoadCounts();
        _isOnline = await Sync.CheckConnectivityAsync();
    }

    private async Task LoadCounts()
    {
        var all = await Storage.GetAllInspectionsAsync();
        _totalCount = all.Count;
        _unsyncedCount = all.Count(i => !i.IsSynced);
    }

    private async Task DoSync()
    {
        _isSyncing = true;
        _lastResult = await Sync.SyncAsync();
        _isSyncing = false;
        await LoadCounts();
    }
}

