arguments.new_str:
using System.Collections.Concurrent;
using SiteInspector.Client.Models;
using SiteInspector.Client.Pages;
using SiteInspector.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

// In-memory store for synced inspections (replace with database in production)
var inspectionStore = new ConcurrentDictionary<string, Inspection>();

// API endpoints for sync
app.MapGet("/api/health", () => Results.Ok(new { status = "healthy" }));

app.MapPost("/api/inspections", (Inspection inspection) =>
{
    inspectionStore[inspection.Id] = inspection;
    return Results.Created($"/api/inspections/{inspection.Id}", inspection);
});

app.MapGet("/api/inspections", () => Results.Ok(inspectionStore.Values.ToList()));

app.MapGet("/api/inspections/{id}", (string id) =>
{
    return inspectionStore.TryGetValue(id, out var inspection)
        ? Results.Ok(inspection)
        : Results.NotFound();
});

app.Run();

